#include<bits/stdc++.h>
using namespace std;
long long n,a[100010],s[100010],f[100010],ans;
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    n++;
    a[n]=0;
    stack<int> stk;
    stk.push(0);
    for(long long i=1;i<=n;i++)
    {
        s[i]=s[i-1]+a[i];
        while(a[stk.top()]>a[i])
        {
            f[stk.top()]+=(s[i-1]-s[stk.top()]);
            stk.pop();
        }
        f[i]=s[i]-s[stk.top()];
        stk.push(i);
    }
    for(int i=1;i<n;i++)
    {
        ans=max(ans,a[i]*f[i]);
    }
    printf("%lld",ans);
    return 0;
}
